module RefModule (
    input clk,
    input load,
    input shift,
    input [3:0] load_value,
    output reg [3:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        q <= load_value;
    else if (shift)
        q <= {1'b0, q[3:1]};
end
endmodule
